// Тестовый корейский текст из Тест2.docx (первые ~500 символов)
const koreanText = `"감사합니다. 또 오세요!"
경쾌한 직원의 목소리와 함께 마트의 자동문이 열렸다. 회색 후드를 눌러쓰고 온갖 식재료가 가득 담긴 딸기무늬 장바구니를 든 한 청년이 정류장 쪽으로 향했다.
"현재 교차로에 게이트가 발생해 교통을 통제하고 있습니다. 협조해주십시오."
늘 가던 길에 벌어진 익숙하지 않은 풍경에 청년이 고개를 기웃거렸다. 정장 위에 형광 연두색 안전 조끼를 입고, 노란 안전모까지 챙겨 쓴 누군가가 빨갛게 빛나는 경광봉을 흔들며 통행로를 막고 있었다. 머리 너머로 푸른빛으로 일렁이는 게이트의 입구가 보였다.
그리고 그 아래에서 헌터들이 그 틈을 비집고 기어 나온 몬스터와 필사적으로 싸우고 있었다.`;

const systemPrompt = `Ты профессиональный переводчик с корейского на русский.
Правила перевода:
- Переводи литературно, сохраняя стиль оригинала
- Используй русский естественный язык
- Сохраняй имена и термины как в оригинале
- Не добавляй пояснений от себя
- Переводи весь текст целиком`;

const modelConfig = {
  mainModel: 'ollama',
  mainModelName: 'llama3.2:3b',
  baseUrl: 'http://127.0.0.1:11434',
  fallbackModel: 'ollama',
  fallbackModelName: 'llama3.2:3b',
  fallbackBaseUrl: 'http://127.0.0.1:11434'
};

return [{
  json: {
    chunk_text: koreanText,
    system_prompt: systemPrompt,
    user_prompt: '',
    glossary: '',
    model_config: modelConfig,
    test_id: 'ollama-test-001',
    file_name: 'Тест2.docx',
    test_start: new Date().toISOString()
  }
}];

const input = $input.first().json;
console.log(`🧪 TEST START: ${input.test_id}`);
console.log(`📄 File: ${input.file_name}`);
console.log(`📝 Input length: ${input.chunk_text.length} chars`);
console.log(`🤖 Model: ${input.model_config.mainModelName}`);
return $input.all();

const test = $('Подготовка тестовых данных').first().json;
const result = $input.first().json;

const report = `
═══════════════════════════════════
🧪 ТЕСТОВЫЙ ПЕРЕВОД — ОТЧЁТ
═══════════════════════════════════
📄 Файл: ${test.file_name}
🆚 Test ID: ${test.test_id}
🤖 Модель: ${result.model_used || test.model_config.mainModelName}
⏱️  Время: ${result.duration_ms || 'N/A'} ms
📥 Вход: ${result.input_length || test.chunk_text.length} символов
📤 Выход: ${result.output_length || (result.output ? result.output.length : 0)} символов
✅ Успех: ${result.success}
🔍 Качество: ${result.quality_check || 'N/A'}

─── ОРИГИНАЛ (KO) ───
${test.chunk_text.substring(0, 300)}...

─── ПЕРЕВОД (RU) ───
${result.output || 'ERROR: ' + (result.error || 'No output')}
═══════════════════════════════════
`.trim();

return [{ json: { ...result, report, test_id: test.test_id, model_name: test.model_config.mainModelName } }];

const result = $input.first().json;
console.log(result.report);
return [{ json: { test_completed: true, ...result } }];
